#include <stdio.h>
#include <limits.h>

#define INF INT_MAX
#define MAX_VERTICES 100

struct Edge {
    int src, dest, weight;
};

void bellmanFord(int V, int E, struct Edge edges[], int src) {
    int distance[MAX_VERTICES];
    int predecessor[MAX_VERTICES];

    // Initialization
    for (int i = 0; i < V; i++) {
        distance[i] = INF;
        predecessor[i] = -1;
    }
    distance[src] = 0;

    // V-1 iterations
    for (int i = 0; i < V - 1; i++) {
        for (int j = 0; j < E; j++) {
            int u = edges[j].src;
            int v = edges[j].dest;
            int w = edges[j].weight;

            if (distance[u] != INF && 
                distance[u] + w < distance[v]) {
                distance[v] = distance[u] + w;
                predecessor[v] = u;
            }
        }
    }

    // Check for negative cycle
    for (int j = 0; j < E; j++) {
        int u = edges[j].src;
        int v = edges[j].dest;
        int w = edges[j].weight;

        if (distance[u] != INF && 
            distance[u] + w < distance[v]) {
            printf("Negative cycle detected!\n");
            return;
        }
    }

    // Print results
    printf("Vertex\tDistance\tPredecessor\n");
    for (int i = 0; i < V; i++) {
        printf("%d\t%d\t\t%d\n", i, distance[i], predecessor[i]);
    }
}

import java.util.*;

public class BellmanFord {
    static class Edge {
        int src, dest, weight;
        Edge(int src, int dest, int weight) {
            this.src = src;
            this.dest = dest;
            this.weight = weight;
        }
    }

    public static Map<Integer, Integer> bellmanFord(
            List<Edge> edges, int V, int src) {
        // Initialize distances
        Map<Integer, Integer> dist = new HashMap<>();
        Map<Integer, Integer> pred = new HashMap<>();

        for (int i = 0; i < V; i++) {
            dist.put(i, Integer.MAX_VALUE);
            pred.put(i, -1);
        }
        dist.put(src, 0);

        // Relax edges V-1 times
        for (int i = 0; i < V - 1; i++) {
            for (Edge edge : edges) {
                if (dist.get(edge.src) != Integer.MAX_VALUE &&
                    dist.get(edge.src) + edge.weight < 
                    dist.get(edge.dest)) {
                    dist.put(edge.dest, 
                        dist.get(edge.src) + edge.weight);
                    pred.put(edge.dest, edge.src);
                }
            }
        }

        // Check for negative cycle
        for (Edge edge : edges) {
            if (dist.get(edge.src) != Integer.MAX_VALUE &&
                dist.get(edge.src) + edge.weight < 
                dist.get(edge.dest)) {
                throw new RuntimeException(
                    "Negative cycle detected!");
            }
        }

        return dist;
    }

    // Path reconstruction method
    public static void printPath(Map<Integer, Integer> pred, 
            int src, int dest) {
        List<Integer> path = new ArrayList<>();
        int curr = dest;
        while (curr != src && curr != -1) {
            path.add(curr);
            curr = pred.get(curr);
        }
        if (curr == src) {
            path.add(src);
            Collections.reverse(path);
            System.out.println("Path: " + path);
        }
    }
}
